/// <summary>
/// Extension of the <c>PurchTable</c> table for the ETGSPAIN model.
/// </summary>
[ExtensionOf(tableStr(PurchTable))]
final class PurchTable_Table_ETGSPAIN_Extension
{
}

Method.Source:
/// <summary>
/// Generates the new Default Dimension with the specified attribute value.
/// </summary>
/// <param name="_dimAttrName">Name of the Financial Dimension.</param>
/// <param name="_newDimensionValue">New value to insert.</param>
/// <param name="_newDimensionDescription">Description of the new value to insert.</param>
public void ETGSPAINsetDimensionValue(Name _dimAttrName, DimensionValue _newDimensionValue, Description _newDimensionDescription)
{
    DimensionAttribute                  dimensionAttribute = DimensionAttribute::findByName(_dimAttrName);
    DimensionFinancialTag               dimensionFinancialTag;
    DimensionFinancialTag               dimensionFinancialTagValue;
    RecId                               dimFinancialCategoryRecid;
    IFRDimensionDefaultDimensionBuilder ifrDimensionDefaultDimensionBuilder;        

    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        if (dimensionAttribute)
        {
            dimFinancialCategoryRecid = dimensionAttribute.financialTagCategory();

            // Comprobamos que exista el Valor en los valores de la Dimensión Financiera
            select firstonly dimensionFinancialTag
            where        dimensionFinancialTag.FinancialTagCategory == dimFinancialCategoryRecid
            &&           dimensionFinancialTag.Value                == _newDimensionValue;

            // Si no existe, lo generamos antes de asignarlo.
            if(!dimensionFinancialTag.RecId)
            {
                dimensionFinancialTagValue.clear();
                dimensionFinancialTagValue.initValue();
                dimensionFinancialTagValue.Value                = _newDimensionValue;
                dimensionFinancialTagValue.Description          = _newDimensionDescription;
                dimensionFinancialTagValue.FinancialTagCategory = dimFinancialCategoryRecid;
                dimensionFinancialTagValue.insert();
            }

            ifrDimensionDefaultDimensionBuilder = IFRDimensionDefaultDimensionBuilder::construct(this.DefaultDimension);
            this.DefaultDimension               = ifrDimensionDefaultDimensionBuilder.addDimensionValue(_dimAttrName, _newDimensionValue).getDefaultDimension();
        }
    }
}
